const r5Test614: fhir5.ConceptMap = {"resourceType":"ConceptMap","id":"101","text":{"status":"extensions","div":"<div xmlns=\"http://www.w3.org/1999/xhtml\">\n      <h2>FHIRv3AddressUse (http://hl7.org/fhir/ConceptMap/101)</h2>\n      <p>Mapping from \n        <a href=\"valueset-address-use.html\">AddressUse</a> to \n        <a href=\"http://terminology.hl7.org/5.1.0/ValueSet-v3-AddressUse.html\">AddressUse</a>\n      </p>\n      <p>DRAFT (not intended for production usage). Published on 2012-06-13 by HL7, Inc (FHIR project team (example): \n        <a href=\"http://hl7.org/fhir\">http://hl7.org/fhir</a>). Creative Commons 0\n      </p>\n      <div>\n        <p>A mapping between the FHIR and HL7 v3 AddressUse Code systems</p>\n\n      </div>\n      <br/>\n      <p>\n        <b>Group 1</b>Mapping from \n        <a href=\"codesystem-address-use.html\">AddressUse</a> to \n        <a href=\"http://terminology.hl7.org/5.1.0/CodeSystem-v3-AddressUse.html\">AddressUse</a>\n      </p>\n      <table class=\"grid\">\n        <tr>\n          <td>\n            <b>Source Code</b>\n          </td>\n          <td>\n            <b>Relationship</b>\n          </td>\n          <td>\n            <b>Target Code</b>\n          </td>\n          <td>\n            <b>Comment</b>\n          </td>\n        </tr>\n        <tr>\n          <td>home</td>\n          <td>\n            <a href=\"codesystem-concept-map-relationship.html#equivalent\" title=\"equivalent\">is equivalent to</a>\n          </td>\n          <td>H (home address)</td>\n          <td/>\n        </tr>\n        <tr>\n          <td>work</td>\n          <td>\n            <a href=\"codesystem-concept-map-relationship.html#equivalent\" title=\"equivalent\">is equivalent to</a>\n          </td>\n          <td>WP (work place)</td>\n          <td/>\n        </tr>\n        <tr>\n          <td>temp (Temporary)</td>\n          <td>\n            <a href=\"codesystem-concept-map-relationship.html#equivalent\" title=\"equivalent\">is equivalent to</a>\n          </td>\n          <td>TMP (temporary address)</td>\n          <td/>\n        </tr>\n        <tr>\n          <td>old (Old / Incorrect)</td>\n          <td>\n            <a href=\"codesystem-concept-map-relationship.html#not-related-to\" title=\"not-related-to\">is not related to</a>\n          </td>\n          <td>BAD (bad address)</td>\n          <td>In the HL7 v3 AD, old is handled by the usablePeriod element, but you have to provide a time, there's no simple equivalent of flagging an address as old</td>\n        </tr>\n      </table>\n    </div>"},"url":"http://hl7.org/fhir/ConceptMap/101","identifier":[{"system":"urn:ietf:rfc:3986","value":"urn:oid:2.16.840.1.113883.4.642.14.1"},{"system":"urn:ietf:rfc:3986","value":"urn:uuid:53cd62ee-033e-414c-9f58-3ca97b5ffc3b"}],"version":"5.0.0","name":"FHIRv3AddressUse","title":"FHIR/v3 Address Use Mapping","status":"draft","experimental":true,"date":"2012-06-13","publisher":"HL7, Inc","contact":[{"name":"FHIR project team (example)","telecom":[{"system":"url","value":"http://hl7.org/fhir"}]}],"description":"A mapping between the FHIR and HL7 v3 AddressUse Code systems","useContext":[{"code":{"system":"http://terminology.hl7.org/CodeSystem/usage-context-type","code":"venue"},"valueCodeableConcept":{"text":"for CCDA Usage"}}],"jurisdiction":[{"coding":[{"system":"urn:iso:std:iso:3166","code":"US"}]}],"purpose":"To help implementers map from FHIR to HL7 v3/CDA","copyright":"Creative Commons 0","sourceScopeUri":"http://hl7.org/fhir/ValueSet/address-use","targetScopeUri":"http://terminology.hl7.org/ValueSet/v3-AddressUse","group":[{"source":"http://hl7.org/fhir/address-use","target":"http://terminology.hl7.org/CodeSystem/v3-AddressUse","element":[{"code":"home","display":"Home","target":[{"code":"H","display":"home address","relationship":"equivalent"}]},{"code":"work","display":"Work","target":[{"code":"WP","display":"work place","relationship":"equivalent"}]},{"code":"temp","display":"Temporary","target":[{"code":"TMP","display":"temporary address","relationship":"equivalent"}]},{"code":"old","display":"Old / Incorrect","target":[{"code":"BAD","display":"bad address","relationship":"not-related-to","comment":"In the HL7 v3 AD, old is handled by the usablePeriod element, but you have to provide a time, there's no simple equivalent of flagging an address as old"}]}],"unmapped":{"mode":"fixed","code":"temp","display":"temp","relationship":"related-to"}}]};

